                        onPressed: _connecting || _importingQr
                            ? null
                            : _importQrImage,
                        icon: _importingQr
                            ? const SizedBox.square(
                                dimension: 18,
                                child: CircularProgressIndicator(
                                  strokeWidth: 2,
                                ),
                              )
                            : const Icon(Icons.image_search),

